class Solution:
    def calculateMinimumHP(self, dungeon) -> int:
        m, n = len(dungeon), len(dungeon[0])
        dp = [float('inf')] * (n + 1)
        for j in range(n - 1, -1, -1):
            if j == n - 1:
                dp[j] = max(1, 1 - dungeon[m - 1][j])
            else:
                dp[j] = max(1, dp[j + 1] - dungeon[m - 1][j])
        for i in range(m - 2, -1, -1):
            new_dp = [float('inf')] * (n + 1)
            for j in range(n - 1, -1, -1):
                best_next = min(dp[j], new_dp[j + 1])
                new_dp[j] = max(1, best_next - dungeon[i][j])
            dp = new_dp
        return dp[0]

